// In meta/checksum.rs:
pub struct Checksum(String);
impl Checksum {
  pub fn from(path: &Path) -> io::Result<Self> {
    if !path.is_file() { return Ok(Checksum(String::new())); }
    let data = std::fs::read(path)?;
    let digest = sha2::Sha256::digest(&data);
    Ok(Checksum(format!("{:x}", digest)))
  }
}
impl Display for Checksum { fn fmt(&self, ...) { write!(f, "{}", &self.0) } }

